async def handle_user_message(user_input: str, session_id: str):
    session = session_store.get(session_id)

    intent_result = await intent_agent.run(
        "Classify: " + user_input,
        session=session
    )

    if intent_result.intent == "rag_query":
        rag_response = await rag_agent.run(
            user_input,
            session=session
        )
        return rag_response
    elif intent_result.intent == "sensitive":
        return "Content filtered for safety"

    return await general_agent.run(user_input, session=session)

class ChatbotSession:
    def __init__(self):
        self.history = []
        self.user_context = {}

    async def add_turn(self, user_msg: str, agent_response: str):
        self.history.append({
            "role": "user", "content": user_msg
        })
        self.history.append({
            "role": "assistant", "content": agent_response
        })
        # Trim history to last 10 turns
        self.history = self.history[-20:]

# Integrated in orchestrator
session_store.register_session_class(ChatbotSession)
